				{
					ConstraintCollection constraints = Tables[i].Constraints;
					int num = 0;
					while (num < constraints.Count)
					{
						if (constraints[num] is ForeignKeyConstraint)
						{
							constraints.Remove(constraints[num]);
						}
						else
						{
							num++;
						}
					}
