					uniqueConstraint = uniqueConstraint2;
				}
				UniqueConstraint primaryKey = _primaryKey;
				_primaryKey = null;
				if (primaryKey != null)
				{
					primaryKey.ConstraintIndex.RemoveRef();
					if (_loadIndex != null)
					{
						_loadIndex.RemoveRef();
						_loadIndex = null;
