			try
			{
				int count = _shadowIndexes.Count;
				for (int i = 0; i < count; i++)
				{
					Index index = _shadowIndexes[i];
					if (0 < index.RefCount)
					{
						index.RecordChanged(record);
					}
				}
			}
			finally
			{
				RestoreShadowIndexes();
			}
		}

