		internal DataTable GetTable(string name, string ns)
		{
			for (int i = 0; i < _list.Count; i++)
			{
				DataTable dataTable = (DataTable)_list[i];
				if (dataTable.TableName == name && dataTable.Namespace == ns)
				{
