		private void ValidateOpen(string caller)
		{
			if (!_isOpen)
			{
				throw ADP.DataReaderClosed(caller);
			}
		}

		private void ValidateReader()
		{
			if (ReaderIsInvalid)
			{
				throw ExceptionBuilder.InvalidDataTableReader(_currentDataTable.TableName);
			}
			if (IsSchemaChanged)
			{
				throw ExceptionBuilder.DataTableReaderSchemaIsInvalid(_currentDataTable.TableName);
			}
		}

		private void ValidateState(string caller)
		{
			ValidateOpen(caller);
			if (_tableCleared)
			{
				throw ExceptionBuilder.EmptyDataTableReader(_currentDataTable.TableName);
			}
			if (_currentDataRow == null || _currentDataTable == null)
			{
				ReaderIsInvalid = true;
				throw ExceptionBuilder.InvalidDataTableReader(_currentDataTable.TableName);
			}
			if (_currentDataRow.RowState == DataRowState.Deleted || _currentDataRow.RowState == DataRowState.Detached || _currentRowRemoved)
			{
				throw ExceptionBuilder.InvalidCurrentRowInDataTableReader();
			}
			if (0 > _rowCounter || _currentDataTable.Rows.Count <= _rowCounter)
			{
				ReaderIsInvalid = true;
				throw ExceptionBuilder.InvalidDataTableReader(_currentDataTable.TableName);
			}
		}

		private void ValidateRow(int rowPosition)
		{
			if (ReaderIsInvalid)
			{
				throw ExceptionBuilder.InvalidDataTableReader(_currentDataTable.TableName);
			}
			if (0 > rowPosition || _currentDataTable.Rows.Count <= rowPosition)
			{
				ReaderIsInvalid = true;
				throw ExceptionBuilder.InvalidDataTableReader(_currentDataTable.TableName);
			}
		}

		internal void SchemaChanged()
		{
			IsSchemaChanged = true;
		}

		internal void DataTableCleared()
		{
			if (_started)
			{
				_rowCounter = -1;
				if (!_reachEORows)
				{
					_currentRowRemoved = true;
				}
			}
		}

		internal void DataChanged(DataRowChangeEventArgs args)
		{
			if (!_started || (_rowCounter == -1 && !_tableCleared))
			{
				return;
			}
			switch (args.Action)
			{
			case DataRowAction.Add:
				ValidateRow(_rowCounter + 1);
				if (_currentDataRow == _currentDataTable.Rows[_rowCounter + 1])
				{
					_rowCounter++;
				}
				break;
			case DataRowAction.Delete:
			case DataRowAction.Rollback:
			case DataRowAction.Commit:
				if (args.Row.RowState != DataRowState.Detached)
				{
					break;
				}
				if (args.Row != _currentDataRow)
				{
					if (_rowCounter != 0)
					{
						ValidateRow(_rowCounter - 1);
						if (_currentDataRow == _currentDataTable.Rows[_rowCounter - 1])
						{
							_rowCounter--;
						}
					}
				}
				else
				{
					_currentRowRemoved = true;
					if (_rowCounter > 0)
					{
						_rowCounter--;
						_currentDataRow = _currentDataTable.Rows[_rowCounter];
					}
					else
					{
						_rowCounter = -1;
						_currentDataRow = null;
					}
				}
				break;
			}
		}
	}
	internal sealed class DataTableReaderListener
	{
		private DataTable _currentDataTable;

		private bool _isSubscribed;

		private WeakReference _readerWeak;

		internal DataTableReaderListener(DataTableReader reader)
		{
			if (reader == null)
			{
				throw ExceptionBuilder.ArgumentNull("DataTableReader");
			}
			if (_currentDataTable != null)
			{
				UnSubscribeEvents();
			}
			_readerWeak = new WeakReference(reader);
			_currentDataTable = reader.CurrentDataTable;
			if (_currentDataTable != null)
			{
				SubscribeEvents();
			}
		}

		internal void CleanUp()
		{
			UnSubscribeEvents();
		}

		internal void UpdataTable(DataTable datatable)
		{
			if (datatable == null)
			{
				throw ExceptionBuilder.ArgumentNull("DataTable");
			}
			UnSubscribeEvents();
			_currentDataTable = datatable;
			SubscribeEvents();
		}

		private void SubscribeEvents()
		{
			if (_currentDataTable != null && !_isSubscribed)
			{
				_currentDataTable.Columns.ColumnPropertyChanged += SchemaChanged;
				_currentDataTable.Columns.CollectionChanged += SchemaChanged;
				_currentDataTable.RowChanged += DataChanged;
				_currentDataTable.RowDeleted += DataChanged;
				_currentDataTable.TableCleared += DataTableCleared;
				_isSubscribed = true;
			}
		}

		private void UnSubscribeEvents()
		{
			if (_currentDataTable != null && _isSubscribed)
			{
				_currentDataTable.Columns.ColumnPropertyChanged -= SchemaChanged;
				_currentDataTable.Columns.CollectionChanged -= SchemaChanged;
				_currentDataTable.RowChanged -= DataChanged;
				_currentDataTable.RowDeleted -= DataChanged;
				_currentDataTable.TableCleared -= DataTableCleared;
				_isSubscribed = false;
			}
		}

		private void DataTableCleared(object sender, DataTableClearEventArgs e)
		{
			DataTableReader dataTableReader = (DataTableReader)_readerWeak.Target;
			if (dataTableReader != null)
			{
				dataTableReader.DataTableCleared();
			}
			else
			{
				UnSubscribeEvents();
			}
		}

		private void SchemaChanged(object sender, CollectionChangeEventArgs e)
		{
			DataTableReader dataTableReader = (DataTableReader)_readerWeak.Target;
			if (dataTableReader != null)
			{
				dataTableReader.SchemaChanged();
			}
			else
			{
				UnSubscribeEvents();
			}
		}

		private void DataChanged(object sender, DataRowChangeEventArgs args)
		{
			DataTableReader dataTableReader = (DataTableReader)_readerWeak.Target;
			if (dataTableReader != null)
			{
				dataTableReader.DataChanged(args);
			}
			else
			{
				UnSubscribeEvents();
			}
		}
	}
