				DataTypePrecedence.SqlInt32 => StorageType.SqlInt32, 
				DataTypePrecedence.SqlInt16 => StorageType.SqlInt16, 
				DataTypePrecedence.SqlByte => StorageType.SqlByte, 
				DataTypePrecedence.SqlBoolean => StorageType.SqlBoolean, 
				DataTypePrecedence.SqlString => StorageType.SqlString, 
				DataTypePrecedence.SqlGuid => StorageType.SqlGuid, 
				DataTypePrecedence.SqlBinary => StorageType.SqlBinary, 
				DataTypePrecedence.SqlMoney => StorageType.SqlMoney, 
				_ => StorageType.Empty, 
			};
		}

		private bool IsMixed(StorageType left, StorageType right)
		{
			if (!ExpressionNode.IsSigned(left) || !ExpressionNode.IsUnsigned(right))
			{
				if (ExpressionNode.IsUnsigned(left))
				{
					return ExpressionNode.IsSigned(right);
				}
				return false;
			}
			return true;
		}

		private bool IsMixedSql(StorageType left, StorageType right)
		{
			if (!ExpressionNode.IsSignedSql(left) || !ExpressionNode.IsUnsignedSql(right))
			{
				if (ExpressionNode.IsUnsignedSql(left))
				{
					return ExpressionNode.IsSignedSql(right);
				}
				return false;
			}
			return true;
		}

		internal StorageType ResultType(StorageType left, StorageType right, bool lc, bool rc, int op)
		{
			if (left == StorageType.Guid && right == StorageType.Guid && Operators.IsRelational(op))
			{
				return left;
			}
			if (left == StorageType.String && right == StorageType.Guid && Operators.IsRelational(op))
			{
				return left;
			}
			if (left == StorageType.Guid && right == StorageType.String && Operators.IsRelational(op))
			{
				return right;
			}
			int precedence = (int)GetPrecedence(left);
			if (precedence == 0)
			{
				return StorageType.Empty;
			}
			int precedence2 = (int)GetPrecedence(right);
			if (precedence2 == 0)
			{
				return StorageType.Empty;
			}
			if (Operators.IsLogical(op))
			{
				if (left == StorageType.Boolean && right == StorageType.Boolean)
				{
					return StorageType.Boolean;
				}
				return StorageType.Empty;
			}
			if (left == StorageType.DateTimeOffset || right == StorageType.DateTimeOffset)
			{
				if (Operators.IsRelational(op) && left == StorageType.DateTimeOffset && right == StorageType.DateTimeOffset)
				{
					return StorageType.DateTimeOffset;
				}
				return StorageType.Empty;
			}
			if (op == 15 && (left == StorageType.String || right == StorageType.String))
			{
				return StorageType.String;
			}
			DataTypePrecedence dataTypePrecedence = (DataTypePrecedence)Math.Max(precedence, precedence2);
			StorageType precedenceType = GetPrecedenceType(dataTypePrecedence);
			if (Operators.IsArithmetical(op) && precedenceType != StorageType.String && precedenceType != StorageType.Char)
			{
				if (!ExpressionNode.IsNumeric(left))
				{
					return StorageType.Empty;
				}
				if (!ExpressionNode.IsNumeric(right))
				{
					return StorageType.Empty;
				}
			}
			if (op == 18 && ExpressionNode.IsInteger(precedenceType))
			{
				return StorageType.Double;
			}
			if (IsMixed(left, right))
			{
				if (lc && !rc)
				{
					return right;
				}
				if (!lc && rc)
				{
					return left;
				}
				if (ExpressionNode.IsUnsigned(precedenceType))
				{
					if (dataTypePrecedence >= DataTypePrecedence.UInt64)
					{
						throw ExprException.AmbiguousBinop(op, DataStorage.GetTypeStorage(left), DataStorage.GetTypeStorage(right));
					}
					precedenceType = GetPrecedenceType(dataTypePrecedence + 1);
				}
			}
			return precedenceType;
		}

		internal StorageType ResultSqlType(StorageType left, StorageType right, bool lc, bool rc, int op)
		{
			int precedence = (int)GetPrecedence(left);
			if (precedence == 0)
			{
				return StorageType.Empty;
			}
			int precedence2 = (int)GetPrecedence(right);
			if (precedence2 == 0)
			{
				return StorageType.Empty;
			}
			if (Operators.IsLogical(op))
			{
				if ((left != StorageType.Boolean && left != StorageType.SqlBoolean) || (right != StorageType.Boolean && right != StorageType.SqlBoolean))
				{
					return StorageType.Empty;
				}
				if (left == StorageType.Boolean && right == StorageType.Boolean)
				{
					return StorageType.Boolean;
				}
				return StorageType.SqlBoolean;
			}
			if (op == 15)
			{
				if (left == StorageType.SqlString || right == StorageType.SqlString)
				{
					return StorageType.SqlString;
				}
				if (left == StorageType.String || right == StorageType.String)
				{
					return StorageType.String;
				}
			}
			if ((left == StorageType.SqlBinary && right != StorageType.SqlBinary) || (left != StorageType.SqlBinary && right == StorageType.SqlBinary))
			{
				return StorageType.Empty;
			}
			if ((left == StorageType.SqlGuid && right != StorageType.SqlGuid) || (left != StorageType.SqlGuid && right == StorageType.SqlGuid))
			{
				return StorageType.Empty;
			}
			if (precedence > 19 && precedence2 < 20)
			{
				return StorageType.Empty;
			}
			if (precedence < 20 && precedence2 > 19)
			{
				return StorageType.Empty;
			}
			if (precedence > 19)
			{
				if (op == 15 || op == 16)
				{
					if (left == StorageType.TimeSpan)
					{
						return right;
					}
					if (right == StorageType.TimeSpan)
					{
						return left;
					}
					return StorageType.Empty;
				}
				if (!Operators.IsRelational(op))
				{
					return StorageType.Empty;
				}
				return left;
			}
			DataTypePrecedence dataTypePrecedence = (DataTypePrecedence)Math.Max(precedence, precedence2);
			StorageType precedenceType = GetPrecedenceType(dataTypePrecedence);
			precedenceType = GetPrecedenceType((DataTypePrecedence)SqlResultType((int)dataTypePrecedence));
			if (Operators.IsArithmetical(op) && precedenceType != StorageType.String && precedenceType != StorageType.Char && precedenceType != StorageType.SqlString)
			{
				if (!ExpressionNode.IsNumericSql(left))
				{
					return StorageType.Empty;
				}
				if (!ExpressionNode.IsNumericSql(right))
				{
					return StorageType.Empty;
				}
			}
			if (op == 18 && ExpressionNode.IsIntegerSql(precedenceType))
			{
				return StorageType.SqlDouble;
			}
			if (precedenceType == StorageType.SqlMoney && left != StorageType.SqlMoney && right != StorageType.SqlMoney)
			{
				precedenceType = StorageType.SqlDecimal;
			}
			if (IsMixedSql(left, right) && ExpressionNode.IsUnsignedSql(precedenceType))
			{
				if (dataTypePrecedence >= DataTypePrecedence.UInt64)
				{
					throw ExprException.AmbiguousBinop(op, DataStorage.GetTypeStorage(left), DataStorage.GetTypeStorage(right));
				}
				precedenceType = GetPrecedenceType(dataTypePrecedence + 1);
			}
			return precedenceType;
		}

		private int SqlResultType(int typeCode)
		{
			switch (typeCode)
			{
			case 23:
				return 24;
			case 20:
				return 21;
			case 18:
				return 19;
			case 16:
				return 17;
			case 14:
				return 15;
			case 12:
				return 13;
			case 9:
			case 10:
				return 11;
			case 6:
			case 7:
				return 8;
			case 3:
			case 4:
				return 5;
			case 1:
				return 2;
			case -2:
				return -1;
			case -5:
				return -4;
			case -8:
				return -7;
			default:
				return typeCode;
			}
		}
	}
	internal sealed class LikeNode : BinaryNode
	{
		private int _kind;

		private string _pattern;

		internal LikeNode(DataTable table, int op, ExpressionNode left, ExpressionNode right)
			: base(table, op, left, right)
		{
		}

		internal override object Eval(DataRow row, DataRowVersion version)
		{
			object obj = _left.Eval(row, version);
			if (obj == DBNull.Value || (_left.IsSqlColumn && DataStorage.IsObjectSqlNull(obj)))
			{
				return DBNull.Value;
			}
			string text;
			if (_pattern == null)
			{
				object obj2 = _right.Eval(row, version);
				if (!(obj2 is string) && !(obj2 is SqlString))
				{
					SetTypeMismatchError(_op, obj.GetType(), obj2.GetType());
				}
				if (obj2 == DBNull.Value || DataStorage.IsObjectSqlNull(obj2))
				{
					return DBNull.Value;
				}
				string pat = (string)SqlConvert.ChangeType2(obj2, StorageType.String, typeof(string), base.FormatProvider);
				text = AnalyzePattern(pat);
				if (_right.IsConstant())
				{
					_pattern = text;
				}
			}
			else
			{
				text = _pattern;
			}
			if (!(obj is string) && !(obj is SqlString))
			{
				SetTypeMismatchError(_op, obj.GetType(), typeof(string));
			}
			char[] trimChars = new char[2] { ' ', '\u3000' };
			string text2 = ((!(obj is SqlString sqlString)) ? ((string)obj) : sqlString.Value);
			string s = text2.TrimEnd(trimChars);
			switch (_kind)
			{
			case 5:
				return true;
			case 4:
				return base.table.Compare(s, text) == 0;
			case 3:
				return 0 <= base.table.IndexOf(s, text);
			case 1:
				return base.table.IndexOf(s, text) == 0;
			case 2:
			{
				string s2 = text.TrimEnd(trimChars);
				return base.table.IsSuffix(s, s2);
			}
			default:
				return DBNull.Value;
			}
		}

		internal string AnalyzePattern(string pat)
		{
			int length = pat.Length;
			char[] array = new char[length + 1];
			pat.CopyTo(0, array, 0, length);
			array[length] = '\0';
			char[] array2 = new char[length + 1];
			int num = 0;
			int num2 = 0;
			int i = 0;
			while (i < length)
			{
				if (array[i] == '*' || array[i] == '%')
				{
					for (; (array[i] == '*' || array[i] == '%') && i < length; i++)
					{
					}
					if ((i < length && num > 0) || num2 >= 2)
					{
						throw ExprException.InvalidPattern(pat);
					}
					num2++;
				}
				else if (array[i] == '[')
				{
					i++;
					if (i >= length)
					{
						throw ExprException.InvalidPattern(pat);
					}
					array2[num++] = array[i++];
					if (i >= length)
					{
						throw ExprException.InvalidPattern(pat);
					}
					if (array[i] != ']')
					{
						throw ExprException.InvalidPattern(pat);
					}
					i++;
				}
				else
				{
					array2[num++] = array[i];
					i++;
				}
			}
			string result = new string(array2, 0, num);
			if (num2 == 0)
			{
				_kind = 4;
				return result;
			}
			if (num > 0)
			{
				if (array[0] == '*' || array[0] == '%')
				{
					if (array[length - 1] == '*' || array[length - 1] == '%')
					{
						_kind = 3;
						return result;
					}
					_kind = 2;
					return result;
				}
				_kind = 1;
				return result;
			}
			_kind = 5;
			return result;
		}
	}
	internal sealed class ConstNode : ExpressionNode
	{
		internal readonly object _val;

		internal ConstNode(DataTable table, ValueType type, object constant)
			: this(table, type, constant, fParseQuotes: true)
		{
		}

		internal ConstNode(DataTable table, ValueType type, object constant, bool fParseQuotes)
			: base(table)
		{
			switch (type)
			{
			case ValueType.Null:
				_val = DBNull.Value;
				break;
			case ValueType.Numeric:
				_val = SmallestNumeric(constant);
				break;
			case ValueType.Decimal:
				_val = SmallestDecimal(constant);
				break;
			case ValueType.Float:
				_val = Convert.ToDouble(constant, NumberFormatInfo.InvariantInfo);
				break;
			case ValueType.Bool:
				_val = Convert.ToBoolean(constant, CultureInfo.InvariantCulture);
				break;
			case ValueType.Str:
				if (fParseQuotes)
				{
					_val = ((string)constant).Replace("''", "'");
				}
				else
				{
					_val = (string)constant;
				}
				break;
			case ValueType.Date:
				_val = DateTime.Parse((string)constant, CultureInfo.InvariantCulture);
				break;
			default:
				_val = constant;
				break;
			}
		}

		internal override void Bind(DataTable table, List<DataColumn> list)
		{
			BindTable(table);
		}

		internal override object Eval()
		{
			return _val;
		}

		internal override object Eval(DataRow row, DataRowVersion version)
		{
			return Eval();
		}

		internal override object Eval(int[] recordNos)
		{
			return Eval();
		}

		internal override bool IsConstant()
		{
			return true;
		}

		internal override bool IsTableConstant()
		{
			return true;
		}

		internal override bool HasLocalAggregate()
		{
			return false;
		}

		internal override bool HasRemoteAggregate()
		{
			return false;
		}

		internal override ExpressionNode Optimize()
		{
			return this;
		}

		private object SmallestDecimal(object constant)
		{
			if (constant == null)
			{
				return 0.0;
			}
			if (constant is string s)
			{
				if (decimal.TryParse(s, NumberStyles.Number, NumberFormatInfo.InvariantInfo, out var result))
				{
					return result;
				}
				if (double.TryParse(s, NumberStyles.Float | NumberStyles.AllowThousands, NumberFormatInfo.InvariantInfo, out var result2))
				{
					return result2;
				}
			}
			else if (constant is IConvertible convertible)
			{
				try
				{
					return convertible.ToDecimal(NumberFormatInfo.InvariantInfo);
				}
				catch (ArgumentException e)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e);
				}
				catch (FormatException e2)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e2);
				}
				catch (InvalidCastException e3)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e3);
				}
				catch (OverflowException e4)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e4);
				}
				try
				{
					return convertible.ToDouble(NumberFormatInfo.InvariantInfo);
				}
				catch (ArgumentException e5)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e5);
				}
				catch (FormatException e6)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e6);
				}
				catch (InvalidCastException e7)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e7);
				}
				catch (OverflowException e8)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e8);
				}
			}
			return constant;
		}

		private object SmallestNumeric(object constant)
		{
			if (constant == null)
			{
				return 0;
			}
			if (constant is string s)
			{
				if (int.TryParse(s, NumberStyles.Integer, NumberFormatInfo.InvariantInfo, out var result))
				{
					return result;
				}
				if (long.TryParse(s, NumberStyles.Integer, NumberFormatInfo.InvariantInfo, out var result2))
				{
					return result2;
				}
				if (double.TryParse(s, NumberStyles.Float | NumberStyles.AllowThousands, NumberFormatInfo.InvariantInfo, out var result3))
				{
					return result3;
				}
			}
			else if (constant is IConvertible convertible)
			{
				try
				{
					return convertible.ToInt32(NumberFormatInfo.InvariantInfo);
				}
				catch (ArgumentException e)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e);
				}
				catch (FormatException e2)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e2);
				}
				catch (InvalidCastException e3)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e3);
				}
				catch (OverflowException e4)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e4);
				}
				try
				{
					return convertible.ToInt64(NumberFormatInfo.InvariantInfo);
				}
				catch (ArgumentException e5)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e5);
				}
				catch (FormatException e6)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e6);
				}
				catch (InvalidCastException e7)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e7);
				}
				catch (OverflowException e8)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e8);
				}
				try
				{
					return convertible.ToDouble(NumberFormatInfo.InvariantInfo);
				}
				catch (ArgumentException e9)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e9);
				}
				catch (FormatException e10)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e10);
				}
				catch (InvalidCastException e11)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e11);
				}
				catch (OverflowException e12)
				{
					ExceptionBuilder.TraceExceptionWithoutRethrow(e12);
				}
			}
			return constant;
		}
	}
	internal sealed class DataExpression : IFilter
	{
		internal string _originalExpression;

		private bool _parsed;

		private bool _bound;

		private ExpressionNode _expr;

		private DataTable _table;

		private readonly StorageType _storageType;

		private readonly Type _dataType;

		private DataColumn[] _dependency = Array.Empty<DataColumn>();

		internal string Expression
		{
			get
			{
				if (_originalExpression == null)
				{
					return "";
				}
				return _originalExpression;
			}
		}

		internal ExpressionNode ExpressionNode => _expr;

		internal bool HasValue => _expr != null;

		internal DataExpression(DataTable table, string expression)
			: this(table, expression, null)
		{
		}

		internal DataExpression(DataTable table, string expression, Type type)
		{
			ExpressionParser expressionParser = new ExpressionParser(table);
			expressionParser.LoadExpression(expression);
			_originalExpression = expression;
			_expr = null;
			if (expression != null)
			{
				_storageType = DataStorage.GetStorageType(type);
				if (_storageType == StorageType.BigInteger)
				{
					throw ExprException.UnsupportedDataType(type);
				}
				_dataType = type;
				_expr = expressionParser.Parse();
				_parsed = true;
				if (_expr != null && table != null)
				{
					Bind(table);
				}
				else
				{
					_bound = false;
				}
			}
		}

		internal void Bind(DataTable table)
		{
			_table = table;
			if (table != null && _expr != null)
			{
				List<DataColumn> list = new List<DataColumn>();
				_expr.Bind(table, list);
				_expr = _expr.Optimize();
				_table = table;
				_bound = true;
				_dependency = list.ToArray();
			}
		}

		internal bool DependsOn(DataColumn column)
		{
			if (_expr != null)
			{
				return _expr.DependsOn(column);
			}
			return false;
		}

		internal object Evaluate()
		{
			return Evaluate((DataRow)null, DataRowVersion.Default);
		}

		internal object Evaluate(DataRow row, DataRowVersion version)
		{
			if (!_bound)
			{
				Bind(_table);
			}
			object obj;
			if (_expr != null)
			{
				obj = _expr.Eval(row, version);
				if (obj != DBNull.Value || StorageType.Uri < _storageType)
				{
					try
					{
						if (StorageType.Object != _storageType)
						{
							obj = SqlConvert.ChangeType2(obj, _storageType, _dataType, _table.FormatProvider);
						}
					}
					catch (Exception ex) when (ADP.IsCatchableExceptionType(ex))
					{
						ExceptionBuilder.TraceExceptionForCapture(ex);
						throw ExprException.DatavalueConvertion(obj, _dataType, ex);
					}
				}
			}
			else
			{
				obj = null;
			}
			return obj;
		}

		internal object Evaluate(DataRow[] rows)
		{
			return Evaluate(rows, DataRowVersion.Default);
		}

		internal object Evaluate(DataRow[] rows, DataRowVersion version)
		{
			if (!_bound)
			{
				Bind(_table);
			}
			if (_expr != null)
			{
				List<int> list = new List<int>();
				foreach (DataRow dataRow in rows)
				{
					if (dataRow.RowState != DataRowState.Deleted && (version != DataRowVersion.Original || dataRow._oldRecord != -1))
					{
						list.Add(dataRow.GetRecordFromVersion(version));
					}
				}
				int[] recordNos = list.ToArray();
				return _expr.Eval(recordNos);
			}
			return DBNull.Value;
		}

		public bool Invoke(DataRow row, DataRowVersion version)
		{
			if (_expr == null)
			{
				return true;
			}
			if (row == null)
			{
				throw ExprException.InvokeArgument();
			}
			object value = _expr.Eval(row, version);
			try
			{
				return ToBoolean(value);
			}
			catch (EvaluateException)
			{
				throw ExprException.FilterConvertion(Expression);
			}
		}

		internal DataColumn[] GetDependency()
		{
			return _dependency;
		}

		internal bool IsTableAggregate()
		{
			if (_expr != null)
			{
				return _expr.IsTableConstant();
			}
			return false;
		}

		internal static bool IsUnknown(object value)
		{
			return DataStorage.IsObjectNull(value);
		}

		internal bool HasLocalAggregate()
		{
			if (_expr != null)
			{
				return _expr.HasLocalAggregate();
			}
			return false;
		}

		internal bool HasRemoteAggregate()
		{
			if (_expr != null)
			{
				return _expr.HasRemoteAggregate();
			}
			return false;
		}

		internal static bool ToBoolean(object value)
		{
			if (IsUnknown(value))
			{
				return false;
			}
			if (value is bool)
			{
				return (bool)value;
			}
			if (value is SqlBoolean sqlBoolean)
			{
				return sqlBoolean.IsTrue;
			}
			if (value is string)
			{
				try
				{
					return bool.Parse((string)value);
				}
				catch (Exception ex) when (ADP.IsCatchableExceptionType(ex))
				{
					ExceptionBuilder.TraceExceptionForCapture(ex);
					throw ExprException.DatavalueConvertion(value, typeof(bool), ex);
				}
