				{
					if (s_funcs[_info]._id == FunctionId.In)
					{
						throw ExprException.InWithoutList();
					}
					throw ExprException.FunctionArgumentCount(_name);
				}
			}
			else if (_argumentCount != s_funcs[_info]._argumentCount)
			{
				throw ExprException.FunctionArgumentCount(_name);
			}
		}
	}
