		{
			return this;
		}

		internal static string ParseName(char[] text, int start, int pos)
		{
			char c = '\0';
			string text2 = string.Empty;
			int num = start;
			int num2 = pos;
			checked
			{
				if (text[start] == '`')
				{
					start++;
					pos--;
					c = '\\';
					text2 = "`";
				}
				else if (text[start] == '[')
				{
					start++;
					pos--;
					c = '\\';
					text2 = "]\\";
				}
			}
			if (c != 0)
			{
				int num3 = start;
				for (int i = start; i < pos; i++)
				{
					if (text[i] == c && i + 1 < pos && text2.IndexOf(text[i + 1]) >= 0)
					{
						i++;
					}
					text[num3] = text[i];
					num3++;
				}
				pos = num3;
			}
			if (pos == start)
			{
				throw ExprException.InvalidName(new string(text, num, num2 - num));
			}
			return new string(text, start, pos - start);
		}
	}
	internal sealed class Operators
	{
		private static readonly int[] s_priority = new int[44]
		{
			0, 20, 20, 9, 12, 11, 11, 13, 13, 13,
			13, 13, 13, 10, 11, 16, 16, 19, 19, 18,
			17, 21, 8, 7, 6, 9, 8, 7, 2, 22,
			23, 23, 24, 24, 24, 24, 24, 24, 24, 24,
			24, 24, 24, 24
		};

		private static readonly string[] s_looks = new string[40]
		{
			"", "-", "+", "Not", "BetweenAnd", "In", "Between", "=", ">", "<",
			">=", "<=", "<>", "Is", "Like", "+", "-", "*", "/", "\\",
			"Mod", "**", "&", "|", "^", "~", "And", "Or", "Proc", "Iff",
			".", ".", "Null", "True", "False", "Date", "GenUniqueId()", "GenGuid()", "Guid {..}", "Is Not"
		};

		internal static bool IsArithmetical(int op)
		{
			if (op != 15 && op != 16 && op != 17 && op != 18)
			{
				return op == 20;
			}
			return true;
		}

		internal static bool IsLogical(int op)
		{
			if (op != 26 && op != 27 && op != 3 && op != 13)
			{
				return op == 39;
			}
			return true;
		}

		internal static bool IsRelational(int op)
		{
			if (7 <= op)
			{
				return op <= 12;
			}
			return false;
		}

		internal static int Priority(int op)
		{
			if (op > s_priority.Length)
			{
				return 24;
			}
			return s_priority[op];
		}

		internal static string ToString(int op)
		{
			if (op <= s_looks.Length)
			{
				return s_looks[op];
			}
			return "Unknown op";
		}
	}
	internal sealed class UnaryNode : ExpressionNode
	{
		internal readonly int _op;

		internal ExpressionNode _right;

		internal UnaryNode(DataTable table, int op, ExpressionNode right)
			: base(table)
		{
			_op = op;
			_right = right;
		}

		internal override void Bind(DataTable table, List<DataColumn> list)
		{
			BindTable(table);
			_right.Bind(table, list);
		}

		internal override object Eval()
		{
			return Eval(null, DataRowVersion.Default);
		}

		internal override object Eval(DataRow row, DataRowVersion version)
		{
			return EvalUnaryOp(_op, _right.Eval(row, version));
		}

		internal override object Eval(int[] recordNos)
		{
			return _right.Eval(recordNos);
		}

		private object EvalUnaryOp(int op, object vl)
		{
			object value = DBNull.Value;
			if (DataExpression.IsUnknown(vl))
			{
				return DBNull.Value;
			}
			switch (op)
			{
			case 0:
				return vl;
