					break;
				case DataRowAction.Rollback:
					CascadeRollback(row);
					break;
				default:
					_ = 16;
					break;
				}
			}
			finally
			{
				row._inCascade = false;
			}
		}

		internal override void CheckConstraint(DataRow childRow, DataRowAction action)
