							}
						}
						else
						{
							XmlSchemaSimpleContentRestriction xmlSchemaSimpleContentRestriction = (XmlSchemaSimpleContentRestriction)content;
							if (HasAttributes(xmlSchemaSimpleContentRestriction.Attributes))
							{
