				flag = num == 0;
				break;
			case EComparison.LT:
				flag = num < 0;
				break;
			case EComparison.LE:
				flag = num <= 0;
				break;
			case EComparison.GT:
				flag = num > 0;
				break;
			case EComparison.GE:
				flag = num >= 0;
				break;
			default:
